const primerItem = $input.first();
let texto = "";
if (primerItem && primerItem.json && primerItem.json.response) {
    texto = primerItem.json.response;
} else if (primerItem && primerItem.json && primerItem.json.text) {
    texto = primerItem.json.text;
}

let minuta = "No se pudo extraer el texto de la minuta pero aquí está el resumen crudo provisto por la IA:";
let data_json = Object.assign({}, {});

// Soporte para ambos formatos de markers (--- o **)
const markers = {
    minuta_start: ["---MINUTA---", "**MINUTA**"],
    json_start: ["---JSON---", "**JSON**"]
};

let minutaStartIdx = -1;
let jsonStartIdx = -1;

for (const m of markers.minuta_start) {
    if (texto.toUpperCase().includes(m.toUpperCase())) {
        minutaStartIdx = texto.toUpperCase().indexOf(m.toUpperCase()) + m.length;
        break;
    }
}

for (const m of markers.json_start) {
    if (texto.toUpperCase().includes(m.toUpperCase())) {
        jsonStartIdx = texto.toUpperCase().indexOf(m.toUpperCase());
        break;
    }
}

if (minutaStartIdx !== -1) {
    if (jsonStartIdx !== -1 && jsonStartIdx > minutaStartIdx) {
        minuta = texto.substring(minutaStartIdx, jsonStartIdx).trim();
    } else {
        minuta = texto.substring(minutaStartIdx).trim();
    }
} else {
    // Fallback: split por la primera llave {
    minuta = texto.split("{")[0].trim();
    for (const m of markers.json_start) {
        if (minuta.toUpperCase().endsWith(m.toUpperCase())) {
            minuta = minuta.substring(0, minuta.length - m.length).trim();
        }
    }
    if (minuta === "") minuta = "Los datos fueron extraídos en formato JSON directo.";
}

try {
    let raw_texto = texto;
    if (raw_texto.includes("```json")) {
        const partes = raw_texto.split("```json");
        if (partes.length > 1) raw_texto = partes[1].split("```")[0];
    } else if (raw_texto.includes("```")) {
        const partes = raw_texto.split("```");
        if (partes.length > 1) raw_texto = partes[1].split("```")[0];
    }
    const firstBrace = raw_texto.indexOf("{");
    const lastBrace = raw_texto.lastIndexOf("}");
    if (firstBrace !== -1 && lastBrace !== -1) {
        data_json = JSON.parse(raw_texto.substring(firstBrace, lastBrace + 1));
    } else {
        data_json = { "error": "No se encontraron llaves JSON en la respuesta de la IA" };
    }
} catch (e) {
    data_json = { "error": "La IA generó un JSON mal formado", "error_msg": String(e) };
}

return [{
    json: {
        "minuta": minuta,
        "json": data_json,
        "raw_llm_text": texto
    }
}];
